import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Установка модов","description":"Пошаговая инструкция по установке модов для Fabric.","frontmatter":{"title":"Установка модов","description":"Пошаговая инструкция по установке модов для Fabric.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"ru_ru/1.20.4/players/installing-mods.md","filePath":"versions/1.20.4/translated/ru_ru/players/installing-mods.md","lastUpdated":1739538073000}`);var s={name:`ru_ru/1.20.4/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установка модов <a class="header-anchor" href="#h1" aria-label="Permalink to “Установка модов”">​</a></h1><p>В этом гайде мы расскажем вам об установке модов для Fabric на официальный лаунчер Minecraft.</p><p>Для сторонних лаунчеров вам следует ознакомиться с их документацией.</p><h2 id="_1-загрузка-модов" tabindex="-1">1. Загрузка модов <a class="header-anchor" href="#_1-загрузка-модов" aria-label="Permalink to “1. Загрузка модов”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Вы должны загружать моды только из источников, которым вы доверяете. Смотрите гайд <a href="./finding-mods">Поиск безопасных модов</a> для большей информации.</p></div><p>Для большинства модов также требуется Fabric API, который можно загрузить с <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> или <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>При загрузке модов убедитесь, что:</p><ul><li>Они работают с той версией Minecraft, на которой вы хотите играть. Например, мод, работающий на версии 1.20, может не работать на версии 1.20.2.</li><li>Они предназначены для Fabric, а не для другого загрузчика модов.</li><li>Кроме того, они предназначены для правильной версии Minecraft (Java Edition).</li></ul><h2 id="_2-перемещение-мода-в-папку-mods" tabindex="-1">2. Перемещение мода в папку <code>mods</code> <a class="header-anchor" href="#_2-перемещение-мода-в-папку-mods" aria-label="Permalink to “2. Перемещение мода в папку mods”">​</a></h2><p>Папку mods можно найти в следующих местах для каждой операционной системы.</p><p>Обычно вы можете вставить эти пути в адресную строку проводника, чтобы быстро перейти к нужной папке.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Как только вы найдете папку <code>mods</code>, вы можете переместить в нее <code>.jar</code> файл мода.</p><p><img src="/assets/players/installing-mods.png" alt="Установленный мод в папке модов" loading="lazy"></p><h2 id="_3-готово" tabindex="-1">3. Готово! <a class="header-anchor" href="#_3-готово" aria-label="Permalink to “3. Готово!”">​</a></h2><p>Как только вы переместите мод в папку <code>mods</code>, вы можете открыть лаунчер Minecraft, выбрать профиль Fabric из списка в левом нижнем углу и нажать Играть!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Лаунчер Minecraft с выбранным профилем Fabric" loading="lazy"></p><h2 id="исправление-ошибок" tabindex="-1">Исправление ошибок <a class="header-anchor" href="#исправление-ошибок" aria-label="Permalink to “Исправление ошибок”">​</a></h2><p>Если вы столкнулись с какими-либо проблемами, попросите помощи в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">дискорде Fabric</a> в канале <code>#player-support</code>.</p><p>Вы также можете попытаться устранить проблему самостоятельно, ознакомившись со страницами, посвященными устранению неполадок:</p><ul><li><a href="./troubleshooting/crash-reports">Краш-репорты</a></li><li><a href="./troubleshooting/uploading-logs">Загрузка логов</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};